import React, { useState } from "react";
import { useQuery } from "@tanstack/react-query";
import "../HomePage/home.scss";
import { fetchGenresList, fetchMovie } from "../../utils/fetchApi";
import { Img_URL } from "../../utils/fetchApi";
import { Link, useNavigate } from "react-router-dom";
const Home = () => {

 const[genreId,setGenreId]=useState('28')

 const navigation = useNavigate();
  const {
    isError,
    isLoading,
    error,
    data: upcoming,
  } = useQuery({
    queryKey: ["Movie", "Upcoming"],
    keepPreviousData: true,
    staleTime:60000,
    queryFn: () =>
    fetchMovie("upcoming").then((res) => {
      return res.results;
    }),

  });

  const { data: Toprated } = useQuery({
    queryKey: ["Movie", "Toprated"],
    keepPreviousData: true,
    staleTime:60000,
    queryFn: () =>
      fetchMovie("top_rated").then((res) => {
        return res.results;
      }),
  });

  const { data: Popular } = useQuery({
    queryKey: ["Movie", "Popular"],
    keepPreviousData: true,
    staleTime:60000,
    queryFn: () =>
      fetchMovie("popular").then((res) => {
        return res.results;
      }),
  });

  const {data:genre}=useQuery({
    queryKey:['genre'],
    queryFn:()=> fetchGenresList().then((res)=>
    {
      return res.genres;
    }),
  });

  const {}=useQuery({
    queryKey:['genres',`${genreId}`],
    queryFn: ()=> fet
  })

  let Row;
  if (isLoading) {
    return (
      <div className="loading">
        <h1>Loading...</h1>
      </div>
    );
  } else if (isError) {
    return (
      <div className="error">
        <p>{error.message}</p>
      </div>
    );
  } else {
    Row = ({ title, arr = [] }) => {
      return (
        <div className="row">
          <h1>{title}</h1>
          <div>
          {arr.map((item) => (
              <Link to={`/movie/${item.id}`} className="card" key={item.title}>
                <img src={`${Img_URL}${item.poster_path}`} alt="img" />
              </Link>
          ))}

          </div>
        </div>
      );
    };
  }
  return (
    <section className="home">
      <div
        className="banner"
        style={{
          backgroundImage: Popular
            && `linear-gradient(rgba(0,0,0,0.2),rgba(0,0,0,0.2)),url(${`${Img_URL}${Popular[0].backdrop_path}`})`,
        }}>
        <div>

         {Popular[0] && <h1>{Popular[0]?.original_title}</h1>}
         {Popular[0] && <p>{Popular[0]?.overview}</p>}
         <div>
          <button onClick={()=> navigation(`/movie/${Popular[0]?.id}`)}>More</button>
          </div>
          </div>
      </div>

        <Row title={"POPULAR"} arr={Popular} />
        <Row title={"TOP RATED"} arr={Toprated} />
        <Row title={"UPCOMING"} arr={upcoming} />
        <select name="genre" id="genre" onChange={(e)=> setGenreId(e.target.value)}>
        {
            genre.map((item)=>(
              <option key={item.id} value={item.id}>{item.name}</option>
            ))
          }
          </select>
        {/* <Row title={"UPCOMING"} arr={upcoming} /> */}
    </section>
  );
};

export default Home;
